// preflightRefreshBuffer is the window before token expiry within which the
// client triggers a proactive Firebase refresh. Five minutes matches the plan
// (R5) and gives the refresh round-trip a generous margin against in-flight
// latency. Exported as a package var (not const) so tests can shrink it.
var preflightRefreshBuffer = 5 * time.Minute

// doRefresh is the single seam through which the client triggers a token
// refresh. Tests inject a Config.RefreshFunc; production code paths fall
// through to auth.Refresh against the real Firebase endpoint. Returning the
// refresh result is unnecessary — Refresh persists into the store, and
// AuthHeader() re-derives from the store on the next call. We only care
// whether the refresh succeeded so we can decide to retry.
func (c *Client) doRefresh(ctx context.Context, email string) error {
	if c.Config == nil || email == "" {
		return fmt.Errorf("client refresh: missing config or email")
	}
	if c.Config.RefreshFunc != nil {
		store := auth.NewStoreAt(c.Config.TokenStorePath())
		_, err := c.Config.RefreshFunc(ctx, email, store)
		return err
	}
	store := auth.NewStoreAt(c.Config.TokenStorePath())
	_, err := auth.Refresh(ctx, email, store)
	return err
}

// needsRefresh reports whether the active account's SuperhumanToken is within
// `buffer` of expiry. Returns false on any error reading the store — the
// caller proceeds with the existing token, and a real expiry will be caught
// by the 401 retry path. This is intentionally lossy: a transient store-read
// error should not block a live request when the cached token may still work.
func (c *Client) needsRefresh(email string, buffer time.Duration) bool {
	if c.Config == nil || email == "" {
		return false
	}
	storePath := c.Config.TokenStorePath()
	if storePath == "" {
		return false
	}
	store := auth.NewStoreAt(storePath)
	acct, ok, err := store.Get(email)
	if err != nil || !ok {
		return false
	}
	if acct.SuperhumanToken.Expires == 0 {
		// Legacy or set-token entries have no expiry recorded; we can't
		// pre-empt them, but a 401 will surface and the retry path can
		// still attempt a refresh (which will then fail with
		// ErrRefreshTokenExpired for bare-JWT accounts — that's the right
		// signal to surface).
		return false
	}
	expiresAt := time.UnixMilli(acct.SuperhumanToken.Expires)
	return time.Until(expiresAt) < buffer
}

// bumpLastUsed records "this account just made a successful API call" by
// updating LastUsedAt on the active account's token-store entry. Used by R2a:
// the four-step resolver in Config.ResolveActiveEmail uses LastUsedAt as the
// step-3 tiebreaker so the CLI defaults to whichever account the user has
// touched most recently.
//
// Best-effort by design: any failure (store I/O, account-not-found,
// missing-config) is swallowed because the caller already has a successful
// HTTP response in hand — surfacing a bump failure would convert a real
// success into a fake error. The next request will retry the bump from
// scratch, so a transient hiccup self-heals on the following call.
//
// Skipped under PRINTING_PRESS_VERIFY=1 so the verifier's deterministic
// snapshots aren't perturbed by a wall-clock timestamp written to disk.
func (c *Client) bumpLastUsed() {
	if c.Config == nil {
		return
	}
	if cliutil.IsVerifyEnv() {
		return
	}
	email, err := c.Config.ResolveActiveEmail()
	if err != nil || email == "" {
		return
	}
	storePath := c.Config.TokenStorePath()
	if storePath == "" {
		return
	}
	store := auth.NewStoreAt(storePath)
	acct, ok, err := store.Get(email)
	if err != nil || !ok {
		return
	}
	acct.LastUsedAt = time.Now().UnixMilli()
	_, _ = store.Upsert(email, acct)
}

// do executes an HTTP request with auto-refresh on token expiry and one
// retry on 401/403. It wraps doOnce to keep the bulk of the HTTP plumbing in
// a single function while isolating the refresh-and-retry policy here.
//
// Recursion-prevention mechanism: do calls doOnce at most twice. The first
// call carries the existing token (after an optional pre-flight refresh).
// On 401/403 it triggers one refresh and re-issues the request via a
// SECOND, FINAL call to doOnce. doOnce never recurses into do; the retry
// counter is a local bool rather than a context value because the wrapping
// scope is small (one method) and a sentinel would have to be plumbed
// through every Get/Post/Put helper. The bool approach localizes the
// invariant to one place.
func (c *Client) do(method, path string, params map[string]string, body any, headerOverrides map[string]string) (json.RawMessage, int, error) {
	ctx := context.Background()

	// Pre-flight: if the active account's token is within the refresh
	// buffer, attempt a refresh before sending the request. A failure here
	// is non-fatal except for ErrRefreshTokenExpired, which the user must
	// act on — surfacing it before any network attempt avoids leaking a
	// stale token to the wire and gives a cleaner error.
	if c.Config != nil {
		email, resolveErr := c.Config.ResolveActiveEmail()
		if resolveErr != nil && errors.Is(resolveErr, config.ErrAccountNotFound) {
			return nil, 0, fmt.Errorf("client: %w (configured account %q)", resolveErr, email)
		}
		if email != "" && c.needsRefresh(email, preflightRefreshBuffer) {
			if refreshErr := c.doRefresh(ctx, email); refreshErr != nil {
				if errors.Is(refreshErr, auth.ErrRefreshTokenExpired) {
					return nil, 0, fmt.Errorf("client: %w (account %s)", refreshErr, email)
				}
				// Best-effort: a transient refresh failure shouldn't
				// block the request. If the existing token is still
				// good enough (clock skew, network blip), we'll get a
				// 2xx; if not, the 401 retry path picks up the slack.
			}
		}
	}

	result, status, err := c.doOnce(method, path, params, body, headerOverrides)

	// 401/403 retry: refresh once, retry once, then surface. Dry-run never
	// produces a 401 (it short-circuits inside doOnce), so we don't need a
	// dry-run guard here.
	if err != nil && (status == http.StatusUnauthorized || status == http.StatusForbidden) && c.Config != nil {
		email, _ := c.Config.ResolveActiveEmail()
		if email != "" {
			if refreshErr := c.doRefresh(ctx, email); refreshErr != nil {
				if errors.Is(refreshErr, auth.ErrRefreshTokenExpired) {
					return nil, status, fmt.Errorf("client: %w (account %s)", refreshErr, email)
				}
				// Refresh failed for a transport-level reason; surface the
				// original 401 because that's the signal the caller can
				// act on (re-attach Chrome / check auth status).
				return result, status, err
			}
			// Refresh succeeded: re-issue the request once. AuthHeader()
			// will re-read the now-rotated token from the store.
			result2, status2, err2 := c.doOnce(method, path, params, body, headerOverrides)
			if err2 != nil && (status2 == http.StatusUnauthorized || status2 == http.StatusForbidden) {
				// Second rejection means the backend isn't accepting this
				// account even with a fresh ID token. That's account-level,
				// not token-level — surface ErrUnauthorized with the email.
				return result2, status2, fmt.Errorf("%w (account %s, HTTP %d)", auth.ErrUnauthorized, email, status2)
			}
			return result2, status2, err2
		}
	}
	return result, status, err
}

// doOnce executes exactly one HTTP request. headerOverrides, when non-nil,
// override global RequiredHeaders for this specific request (used for
// per-endpoint API versioning). All retry policy (refresh-on-401, rate-limit
// backoff, 5xx backoff) is owned by `do` or this function's inner loop —
// callers must not invoke doOnce directly except through `do`.
func (c *Client) doOnce(method, path string, params map[string]string, body any, headerOverrides map[string]string) (json.RawMessage, int, error) {
	targetURL := c.BaseURL + path

	var bodyBytes []byte
	if body != nil {
		b, err := json.Marshal(body)
		if err != nil {
			return nil, 0, fmt.Errorf("marshaling body: %w", err)
		}
		bodyBytes = b
	}

	// Resolve auth material before the dry-run branch so --dry-run can preview
	// exactly what would be sent. Uses only cached credentials; a token that
	// requires a network refresh will be re-fetched on the live request path,
	// not during dry-run.
	authHeader, err := c.authHeader()
	if err != nil {
		return nil, 0, err
	}

	// Build the request for dry-run display or actual execution
	if c.DryRun {
		return c.dryRun(method, targetURL, path, params, bodyBytes, headerOverrides, authHeader, c.previewSuperhumanHeaders(targetURL))
	}

	const maxRetries = 3
	var lastErr error

	for attempt := 0; attempt <= maxRetries; attempt++ {
		// Proactive rate limiting — wait before sending
		c.limiter.Wait()
		var bodyReader io.Reader
		if bodyBytes != nil {
			bodyReader = strings.NewReader(string(bodyBytes))
		}

		req, err := http.NewRequest(method, targetURL, bodyReader)
		if err != nil {
			return nil, 0, fmt.Errorf("creating request: %w", err)
		}
		if bodyBytes != nil {
			req.Header.Set("Content-Type", "application/json")
		}

		if params != nil {
			q := req.URL.Query()
			for k, v := range params {
				if v != "" {
					q.Set(k, v)
				}
			}
			req.URL.RawQuery = q.Encode()
		}

		if authHeader != "" {
			req.Header.Set("Authorization", authHeader)
		}
		req.Header.Set("Content-Type", "text/plain;charset=UTF-8")
		// PATCH(U3): every authenticated /~backend/v3/* call needs the full
		// x-superhuman-* header set. The bundle's wrapper sets six headers on
		// each request; without them, POST endpoints reject the call with 400
		// before any body validation runs. addSuperhumanHeaders pulls the
		// metadata (externalId, deviceId, etc.) from the active account's
		// token-store entry — that data was captured at `auth login --disk`
		// time. Only fires for hosts on *.superhuman.com so we don't leak
		// these headers to unrelated services.
		c.addSuperhumanHeaders(req)
		if c.Config != nil {
			for k, v := range c.Config.Headers {
				req.Header.Set(k, v)
			}
		}
		// Per-endpoint header overrides (e.g., different API version per resource)
		for k, v := range headerOverrides {
			req.Header.Set(k, v)
		}
		if req.Header.Get("User-Agent") == "" {
			req.Header.Set("User-Agent", "superhuman-pp-cli/0.1.0")
		}
		// Go's net/http omits Accept by default; browsers, curl, and other
		// stdlibs always send it. Fingerprint-checking WAFs (Imperva, Akamai,
		// Cloudflare bot-mode, DataDome) flag the absence as a bot signal
		// and answer with empty-body 5xx, 403, or a challenge redirect
		// depending on vendor and rule tier. The value is application/json
		// rather than */* because strict-JSON APIs (Zendesk, Atlassian REST,
		// Salesforce) return 415 on anything that isn't literally
		// application/json; specs that need a different content type
		// (vendor mediatypes, XML, HTML) declare it via RequiredHeaders or
		// per-endpoint headerOverrides, both of which run before this
		// if-empty default.
		if req.Header.Get("Accept") == "" {
			req.Header.Set("Accept", "application/json")
		}

		resp, err := c.HTTPClient.Do(req)
		if err != nil {
			lastErr = fmt.Errorf("%s %s: %w", method, path, err)
			continue
		}

		respBody, err := io.ReadAll(resp.Body)
		resp.Body.Close()
		if err != nil {
			return nil, 0, fmt.Errorf("reading response: %w", err)
		}
		respBody = sanitizeJSONResponse(respBody)

		// Success
		if resp.StatusCode < 400 {
			c.limiter.OnSuccess()
			if method != http.MethodGet && !c.DryRun {
				c.invalidateCache()
			}
			c.bumpLastUsed()
			return json.RawMessage(respBody), resp.StatusCode, nil
		}

		apiErr := &APIError{
			Method:     method,
			Path:       path,
			StatusCode: resp.StatusCode,
			Body:       truncateBody(respBody),
		}

		// Rate limited - adjust adaptive limiter and retry
		if resp.StatusCode == 429 && attempt < maxRetries {
			c.limiter.OnRateLimit()
			wait := cliutil.RetryAfter(resp)
			fmt.Fprintf(os.Stderr, "rate limited, waiting %s (attempt %d/%d, rate adjusted to %.1f req/s)\n", wait, attempt+1, maxRetries, c.limiter.Rate())
			time.Sleep(wait)
			lastErr = apiErr
			continue
		}

		// Server error - retry with backoff
		if resp.StatusCode >= 500 && attempt < maxRetries {
			wait := time.Duration(math.Pow(2, float64(attempt))) * time.Second
			fmt.Fprintf(os.Stderr, "server error %d, retrying in %s (attempt %d/%d)\n", resp.StatusCode, wait, attempt+1, maxRetries)
			time.Sleep(wait)
			lastErr = apiErr
			continue
		}

		// Client error or retries exhausted - return the error
		return nil, resp.StatusCode, apiErr
	}

	return nil, 0, lastErr
}

// dryRun prints the outgoing request exactly as the live path would send it,
// using the auth material already resolved in `do()`. Never triggers a network
// call — the caller is responsible for passing cached auth material only.
func (c *Client) dryRun(method, targetURL, path string, params map[string]string, body []byte, headerOverrides map[string]string, authHeader string, superhumanHeaders map[string]string) (json.RawMessage, int, error) {
	fmt.Fprintf(os.Stderr, "%s %s\n", method, targetURL)
	queryPrinted := false
	if params != nil {
		keys := make([]string, 0, len(params))
		for k := range params {
			if params[k] != "" {
				keys = append(keys, k)
			}
		}
		sort.Strings(keys)
		for _, k := range keys {
			sep := "?"
			if queryPrinted {
				sep = "&"
			}
			fmt.Fprintf(os.Stderr, "  %s%s=%s\n", sep, k, params[k])
			queryPrinted = true
		}
	}
	_ = queryPrinted
	if body != nil {
		var pretty json.RawMessage
		if json.Unmarshal(body, &pretty) == nil {
			enc := json.NewEncoder(os.Stderr)
			enc.SetIndent("  ", "  ")
			fmt.Fprintf(os.Stderr, "  Body:\n")
			enc.Encode(pretty)
		}
	}
	if authHeader != "" {
		fmt.Fprintf(os.Stderr, "  %s: %s\n", "Authorization", maskToken(authHeader))
	}
	// PATCH(U3): emit the x-superhuman-* identity headers so dry-run reflects
	// what doOnce would actually set on the wire. Keys are deterministic order
	// for snapshot stability.
	if len(superhumanHeaders) > 0 {
		keys := make([]string, 0, len(superhumanHeaders))
		for k := range superhumanHeaders {
			keys = append(keys, k)
		}
		sort.Strings(keys)
		for _, k := range keys {
			fmt.Fprintf(os.Stderr, "  %s: %s\n", k, superhumanHeaders[k])
		}
	}
	fmt.Fprintf(os.Stderr, "\n(dry run - no request sent)\n")
	return json.RawMessage(`{"dry_run": true}`), 0, nil
}

// previewSuperhumanHeaders returns the x-superhuman-* identity headers the
// live path would attach for this URL. Used by dryRun so --dry-run output
// reflects all six headers (per plan U3 acceptance criteria), not just the
// Bearer token. Returns nil for non-superhuman hosts. Generates fresh
// session-id / request-id UUIDs each call — these are per-request anyway, and
// the dry-run snapshot just proves "the headers will be set" rather than
// pinning a specific UUID.
func (c *Client) previewSuperhumanHeaders(targetURL string) map[string]string {
	u, err := url.Parse(targetURL)
	if err != nil || !isSuperhumanHost(u) {
		return nil
	}
	if c.Config == nil {
		return nil
	}
	email, err := c.Config.ResolveActiveEmail()
	if err != nil || email == "" {
		return nil
	}
	storePath := c.Config.TokenStorePath()
	if storePath == "" {
		return nil
	}
	store := auth.NewStoreAt(storePath)
	acct, ok, err := store.Get(email)
	if err != nil || !ok {
		return nil
	}
	// Build a temporary http.Request, attach the headers via the canonical
	// setter, then copy the relevant keys back out so dryRun can print them
	// without having to know about auth internals. Cheap throwaway request;
	// never sent.
	tmpReq, err := http.NewRequest("GET", targetURL, nil)
	if err != nil {
		return nil
	}
	result := &auth.CookieAuthResult{
		Email:      email,
		GoogleID:   acct.UserID,
		IDToken:    acct.SuperhumanToken.Token,
		ExternalID: acct.UserExternalID,
		DeviceID:   acct.DeviceID,
	}
	auth.AddSuperhumanBackendHeaders(tmpReq, result)
	out := map[string]string{}
	for _, name := range []string{
		"x-superhuman-version",
		"x-superhuman-user-email",
		"x-superhuman-user-external-id",
		"x-superhuman-session-id",
		"x-superhuman-request-id",
		"x-superhuman-device-id",
	} {
		if v := tmpReq.Header.Get(name); v != "" {
			out[name] = v
		}
	}
	return out
}

func (c *Client) ConfiguredTimeout() time.Duration {
	if c.HTTPClient != nil && c.HTTPClient.Timeout > 0 {
		return c.HTTPClient.Timeout
	}
	return 30 * time.Second
}

func (c *Client) authHeader() (string, error) {
	if c.Config == nil {
		return "", nil
	}
	return c.Config.AuthHeader(), nil
}

// sanitizeJSONResponse strips known JSONP/XSSI prefixes and UTF-8 BOM from
// response bodies so that downstream JSON parsing succeeds. For clean JSON
// responses these checks are no-ops.
func sanitizeJSONResponse(body []byte) []byte {
	// UTF-8 BOM
	body = bytes.TrimPrefix(body, []byte("\xEF\xBB\xBF"))

	// JSONP/XSSI prefixes, ordered longest-first where prefixes overlap
	prefixes := [][]byte{
		[]byte(")]}'\n"),
		[]byte(")]}'"),
		[]byte("{}&&"),
		[]byte("for(;;);"),
		[]byte("while(1);"),
	}
	for _, p := range prefixes {
		if bytes.HasPrefix(body, p) {
			body = bytes.TrimPrefix(body, p)
			body = bytes.TrimLeft(body, " \t\r\n")
			break
		}
	}
	return body
}

// maskToken redacts all but the last 4 characters of a token for safe display.
func maskToken(token string) string {
	if token == "" {
		return ""
	}
	if len(token) <= 4 {
		return "****"
	}
	return "****" + token[len(token)-4:]
}

func truncateBody(b []byte) string {
	s := string(b)
	if len(s) > 200 {
		return s[:200] + "..."
	}
	return s
}

// isSuperhumanHost reports whether the request targets a host on
// *.superhuman.com. We only attach the x-superhuman-* identity headers for
// these hosts so the active-account metadata can't leak to unrelated services
// (test mock servers, BaseURL overrides pointing at example.com, etc.).
//
// Hostname() strips the port so localhost:8080 mock servers in tests do not
// pattern-match anything here, and the suffix check `.superhuman.com` matches
// mail.superhuman.com, accounts.superhuman.com, and any future subdomain
// without matching look-alikes like superhuman.com.evil.com.
func isSuperhumanHost(u *url.URL) bool {
	if u == nil {
		return false
	}
	host := u.Hostname()
	return host == "superhuman.com" || strings.HasSuffix(host, ".superhuman.com")
}

// addSuperhumanHeaders attaches the six x-superhuman-* headers (version,
// user-email, user-external-id, session-id, request-id, device-id) plus the
// Bearer authorization that every authenticated /~backend/v3/* call needs.
//
// Sources the per-account metadata from the token store: U1 captured
// userExternalId + deviceId at `auth login --disk` time, and the active-
// account resolver (R2b) tells us which entry to read. If any prerequisite is
// missing (no Config, no active email, account absent from store), the
// function is a silent no-op — callers see the existing Bearer-only behavior,
// which is the right fallback for test mocks and for the disk-auth-smoke
// probe path that constructs CookieAuthResults directly.
func (c *Client) addSuperhumanHeaders(req *http.Request) {
	if req == nil || !isSuperhumanHost(req.URL) {
		return
	}
	if c.Config == nil {
		return
	}
	email, err := c.Config.ResolveActiveEmail()
	if err != nil || email == "" {
		return
	}
	storePath := c.Config.TokenStorePath()
	if storePath == "" {
		return
	}
	store := auth.NewStoreAt(storePath)
	acct, ok, err := store.Get(email)
	if err != nil || !ok {
		return
	}
	// Synthesise a CookieAuthResult from the stored account so we can reuse
	// the canonical header-setter in the auth package. UserID is the Google
	// ID (the cookie-name on accounts.superhuman.com); the rest of the
	// fields come straight off AccountTokens.
	result := &auth.CookieAuthResult{
		Email:      email,
		GoogleID:   acct.UserID,
		IDToken:    acct.SuperhumanToken.Token,
		ExternalID: acct.UserExternalID,
		DeviceID:   acct.DeviceID,
	}
	auth.AddSuperhumanBackendHeaders(req, result)
}
